import React, { useEffect, useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Pressable,
  ScrollView,
} from "react-native";
import { useNavigation, useRoute } from "@react-navigation/native";
import { useTranslation } from "../i18n";
import { OFFICIAL_CONTROL_MOCK } from "../mock/officialControlMock";

export default function OfficialControlScreen() {
  const navigation = useNavigation();
  const route = useRoute();
  const { t } = useTranslation();

  const ref = route?.params?.ref ?? null;

  const EMPTY = useMemo(
    () => ({
      identificationVehicule: {
        immatriculation: ref || "—",
        marqueModele: "—",
        proprietaire: "—",
      },
      autorisationExercer: {
        numeroLicence: "—",
        validiteDebut: "—",
        validiteFin: "—",
        zone: "—",
        numeroPortiere: "—",
      },
      profilChauffeur: {
        noms: "—",
        numeroPermis: "—",
        categorie: "—",
        numeroCNI: "—",
      },
      assurance: {
        compagnie: "—",
        expiration: "—",
        statut: "—",
      },
    }),
    [ref]
  );

  const [payload, setPayload] = useState(EMPTY);

  useEffect(() => {
    // ✅ For now: use local mock payload instead of API fetch
    setPayload(OFFICIAL_CONTROL_MOCK);
  }, []);

  const v = payload.identificationVehicule || EMPTY.identificationVehicule;
  const a = payload.autorisationExercer || EMPTY.autorisationExercer;
  const d = payload.profilChauffeur || EMPTY.profilChauffeur;
  const i = payload.assurance || EMPTY.assurance;

  // ✅ insurance status -> chip color
  const insuranceStatusRaw = (i?.statut ?? "").toString().trim().toUpperCase();
  const insuranceIsValid = ["VALIDE", "VALID", "ACTIVE"].includes(insuranceStatusRaw);
  const insuranceTone = insuranceIsValid ? "success" : "danger";

  const initials =
    d?.noms && d.noms !== "—"
      ? d.noms
          .split(" ")
          .filter(Boolean)
          .map((x) => x[0])
          .slice(0, 2)
          .join("")
      : "—";

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
      >
        {/* Back */}
        <View style={styles.topRow}>
         <Pressable
  style={styles.backBtn}
  onPress={() => {
    if (navigation.canGoBack()) {
      navigation.goBack();
    }
  }}
>

            <Text style={styles.backIcon}>‹</Text>
            <Text style={styles.backText}>{t("common.back")}</Text>
          </Pressable>
        </View>

        {/* Vehicle */}
        <SectionCard
          icon="🚕"
          title={t("official.vehicle.title")}
          subtitle={`(${t("official.vehicle.subtitle")})`}
          rows={[
            { icon: "🚗", label: t("official.vehicle.plate"), value: v.immatriculation || "—" },
            { icon: "🚕", label: t("official.vehicle.model"), value: v.marqueModele || "—" },
            { icon: "📍", label: t("official.vehicle.owner"), value: v.proprietaire || "—" },
          ]}
        />

        {/* Licence */}
        <SectionCard
          icon="✅"
          title={t("official.licence.title")}
          subtitle={`(${t("official.licence.subtitle")})`}
          rows={[
            { icon: "🚗", label: t("official.licence.number"), value: a.numeroLicence ?? "—" },
            {
              icon: "🕒",
              label: t("official.licence.validity"),
              value:
                a.validiteDebut && a.validiteFin && a.validiteDebut !== "—" && a.validiteFin !== "—"
                  ? `${a.validiteDebut} au ${a.validiteFin}`
                  : "—",
            },
            { icon: "📍", label: t("official.licence.zone"), value: a.zone ?? "—" },
            { icon: "🚕", label: t("official.licence.doorNumber"), value: a.numeroPortiere ?? "—" },
          ]}
          headerVariant="green"
        />

        {/* Driver */}
        <SectionCard
          icon="🧑🏾‍✈️"
          title={t("official.driver.title")}
          subtitle={`(${t("official.driver.subtitle")})`}
          rows={[
            { icon: "🚗", label: t("official.driver.permit"), value: d.numeroPermis ?? "—" },
            { icon: "🅱️", label: t("official.driver.category"), value: d.categorie ?? "—" },
            { icon: "🪪", label: t("official.driver.cni"), value: d.numeroCNI ?? "—" },
          ]}
          headerVariant="green"
          topLeftAvatar={{ initials, name: d.noms ?? "—" }}
        />

        {/* Insurance */}
        <SectionCard
          icon="✅"
          title={t("official.insurance.title")}
          subtitle={`(${t("official.insurance.subtitle")})`}
          rows={[
            { icon: "🚗", label: t("official.insurance.company"), value: i.compagnie ?? "—" },
            { icon: "🕒", label: t("official.insurance.expiry"), value: i.expiration ?? "—" },
            {
              icon: "✅",
              label: t("official.insurance.status"),
              value: i.statut ?? "—",
              isStatus: true,
              statusTone: insuranceTone,
            },
          ]}
          headerVariant="green"
        />
      </ScrollView>
    </SafeAreaView>
  );
}

function SectionCard({ icon, title, subtitle, rows, headerVariant = "green", topLeftAvatar }) {
  return (
    <View style={styles.card}>
      <View style={[styles.sectionHeader, headerVariant === "green" && styles.sectionHeaderGreen]}>
        <Text style={styles.sectionHeaderIcon}>{icon}</Text>
        <View style={{ flex: 1 }}>
          <Text style={styles.sectionHeaderTitle}>
            {title} <Text style={styles.sectionHeaderSub}>{subtitle}</Text>
          </Text>
        </View>
      </View>

      {topLeftAvatar ? (
        <View style={styles.avatarRow}>
          <View style={styles.avatarCircle}>
            <Text style={styles.avatarText}>{topLeftAvatar.initials}</Text>
          </View>
          <Text style={styles.avatarName}>{topLeftAvatar.name}</Text>
        </View>
      ) : null}

      {rows.map((r, idx) => (
        <View
          key={`${r.label}-${idx}`}
          style={[styles.row, idx === rows.length - 1 ? styles.rowLast : null]}
        >
          <Text style={styles.rowIcon}>{r.icon}</Text>
          <Text style={styles.rowLabel} numberOfLines={1}>
            {r.label} :
          </Text>

          {r.isStatus ? (
            <View
              style={[
                styles.statusChip,
                r.statusTone === "danger" && styles.statusChipDanger,
              ]}
            >
              <Text style={styles.statusChipText}>{r.value}</Text>
            </View>
          ) : (
            <Text style={styles.rowValue}>{r.value}</Text>
          )}
        </View>
      ))}
    </View>
  );
}

const DARK_GREEN = "#0F3C2F";
const HEADER_GREEN = "#DCEEDD";
const TEXT_DARK = "#0B1F14";
const MUTED_GREEN = "#4B6B57";
const CARD_BG = "#FFFFFF";
const PAGE_BG = "#EEF5F4";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: PAGE_BG },

  scroll: {
    paddingHorizontal: 18,
    paddingTop: 16,
    paddingBottom: 28,
  },

  topRow: {
    width: "100%",
    flexDirection: "row",
    justifyContent: "flex-start",
    marginBottom: 12,
  },
  backBtn: {
    backgroundColor: DARK_GREEN,
    borderRadius: 26,
    paddingVertical: 10,
    paddingHorizontal: 16,
    flexDirection: "row",
    alignItems: "center",
    gap: 10,
    shadowColor: "#000",
    shadowOpacity: 0.16,
    shadowRadius: 12,
    shadowOffset: { width: 0, height: 8 },
    elevation: 6,
  },
  backIcon: { color: "#fff", fontSize: 20, fontWeight: "900", marginTop: -1 },
  backText: { color: "#fff", fontSize: 18, fontWeight: "900" },

  card: {
    marginTop: 16,
    borderRadius: 22,
    backgroundColor: CARD_BG,
    overflow: "hidden",
    shadowColor: "#000",
    shadowOpacity: 0.06,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 14 },
    elevation: 3,
  },

  sectionHeader: {
    backgroundColor: "#E6EFE9",
    paddingVertical: 10,
    paddingHorizontal: 14,
    flexDirection: "row",
    alignItems: "center",
    gap: 10,
  },
  sectionHeaderGreen: { backgroundColor: HEADER_GREEN },
  sectionHeaderIcon: { fontSize: 20, marginTop: 1 },
  sectionHeaderTitle: { fontSize: 16, fontWeight: "900", color: "#1F6F3D" },
  sectionHeaderSub: { fontSize: 15, fontWeight: "900", color: "#557B64" },

  avatarRow: {
    flexDirection: "row",
    alignItems: "center",
    gap: 12,
    paddingHorizontal: 14,
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: "rgba(15,23,42,0.07)",
  },
  avatarCircle: {
    width: 54,
    height: 54,
    borderRadius: 27,
    backgroundColor: "#ECF1EE",
    borderWidth: 1,
    borderColor: "rgba(0,0,0,0.10)",
    alignItems: "center",
    justifyContent: "center",
